<div class="box" id="root"></div>
<script>
(function(){
  try {
    var raw = decodeURIComponent(escape(atob('$1')));
    var D = JSON.parse(raw);
  } catch(e) { document.getElementById('root').textContent='[result decode error]'; return; }

  var G = {bac:'🃏 百家樂',rou:'🎡 輪盤',sic:'🎲 骰寶',slo:'🎰 拉霸機',
           rdg:'🚪 射龍門',drt:'🐉 龍虎鬥',niu:'🐂 牛牛',settle:'📋 結算室'};
  var root = document.getElementById('root');
  var h = '<div class="title">'+(G[D.g]||D.g)+'</div>';

  function rnk(r){if(r===1)return'A';if(r===11)return'J';if(r===12)return'Q';if(r===13)return'K';return r;}
  function sut(s){return{H:'♥',D:'♦',C:'♣',S:'♠'}[s]||s;}
  function isRed(s){return s==='H'||s==='D';}
  function mkCard(c){
    var cls=isRed(c[1])?'card red':'card black';
    return '<div class="'+cls+'"><span>'+rnk(c[0])+'</span><span style="font-size:10px">'+sut(c[1])+'</span></div>';
  }
  function mkCards(arr){return arr.map(mkCard).join('');}

  if (D.g==='bac') {
    var r=D.r;
    h+='<div class="visuals">';
    h+='<div style="text-align:center"><div style="font-size:10px;color:#aaa;margin-bottom:4px">莊 '+r.bp+' 點</div>'+mkCards(r.bc)+'</div>';
    h+='<div class="vs">VS</div>';
    h+='<div style="text-align:center"><div style="font-size:10px;color:#aaa;margin-bottom:4px">閒 '+r.pp+' 點</div>'+mkCards(r.pc)+'</div>';
    h+='</div>';
    if(r.nat) h+='<div style="text-align:center;font-size:11px;color:#ffd740">✦ Natural ✦</div>';
  }
  else if (D.g==='rou') {
    var r=D.r;
    h+='<div class="visuals"><div class="rnum '+r.c+'">'+r.n+'</div></div>';
  }
  else if (D.g==='sic') {
    var r=D.r;
    var faces=['','⚀','⚁','⚂','⚃','⚄','⚅'];
    h+='<div class="visuals">';
    for(var i=0;i<3;i++) h+='<div class="dice">'+faces[r.d[i]]+'</div>';
    h+='</div>';
    h+='<div style="text-align:center;font-size:12px;color:#aaa">合計 '+r.t+(r.triple?' 全圍！':'')+'</div>';
  }
  else if (D.g==='slo') {
    var r=D.r;
    h+='<div class="visuals">';
    for(var i=0;i<3;i++) h+='<div class="reel">'+r.s[i]+'</div>';
    h+='</div>';
    h+='<div style="text-align:center;font-size:12px;color:#aaa">'+r.tier+(r.mult>0?' ('+r.mult+'x)':'')+'</div>';
  }
  else if (D.g==='rdg') {
    var r=D.r;
    h+='<div class="visuals">';
    h+=mkCard(r.g1)+'<div class="vs">⬅ 門柱 ➡</div>'+mkCard(r.g2);
    h+='</div>';
    h+='<div class="visuals"><div class="vs">射門 →</div>'+mkCard(r.shot)+'</div>';
    if(r.hit) h+='<div style="text-align:center;color:#ef5350;font-size:13px;font-weight:bold">💥 撞柱！包賠雙倍</div>';
  }
  else if (D.g==='drt') {
    var r=D.r;
    h+='<div class="visuals">';
    h+='<div style="text-align:center"><div style="font-size:10px;color:#aaa;margin-bottom:4px">龍</div>'+mkCard(r.dragon)+'</div>';
    h+='<div class="vs">VS</div>';
    h+='<div style="text-align:center"><div style="font-size:10px;color:#aaa;margin-bottom:4px">虎</div>'+mkCard(r.tiger)+'</div>';
    h+='</div>';
  }
  else if (D.g==='niu') {
    var r=D.r;
    function niuN(v){if(v===0)return'無牛';if(v===10)return'牛牛';return'牛'+v;}
    h+='<div class="visuals">';
    h+='<div style="text-align:center"><div style="font-size:10px;color:#aaa;margin-bottom:4px">玩家 '+niuN(r.pn)+'</div>'+mkCards(r.pc)+'</div>';
    h+='</div>';
    h+='<div class="visuals">';
    h+='<div style="text-align:center"><div style="font-size:10px;color:#aaa;margin-bottom:4px">莊家 '+niuN(r.dn)+'</div>'+mkCards(r.dc)+'</div>';
    h+='</div>';
  }
  else if (D.g==='settle') {
    var tp = D.type==='sign'?'簽泥碼':'還債';
    h+='<div style="text-align:center;font-size:15px;margin:8px 0">'+tp+' '+D.amount+'</div>';
    if(D.freedom) h+='<div class="freedom">🆓 自由</div>';
  }

  /* 結果行 */
  if (D.g!=='settle') {
    var net = D.w||0;
    var cls = net>0?'win':net<0?'lose':'push';
    var txt = net>0?'+'+Math.round(net):net<0?Math.round(net):'退注';
    h+='<div class="result '+cls+'">'+txt+'</div>';
  }

  /* 帳本 */
  if (D.l) {
    h+='<div class="ledger">';
    h+='<span class="tag">本金</span> '+D.l.bp+' <span class="arr">→</span> '+D.l.ap+' ';
    h+='<span class="tag">泥碼</span> '+D.l.bm+' <span class="arr">→</span> '+D.l.am+' ';
    h+='<span class="tag">欠債</span> '+D.l.bd+' <span class="arr">→</span> '+D.l.ad;
    h+='</div>';
  }

  root.innerHTML = h;
})();
</script>
</body>
</html>
