<script type="module">
(async function() {
  const DEBT_TOTAL = 3500000;

  window.jnToggle = function() {
    const card = document.getElementById('jnCard');
    if (card) card.classList.toggle('open');
  };

  function formatMoney(n) {
    if (typeof n !== 'number' || isNaN(n)) return '-';
    return '$' + n.toLocaleString('en-US');
  }

  function padPage(id) {
    if (typeof id !== 'number' || isNaN(id)) return 'page.000';
    return 'page.' + String(id).padStart(3, '0');
  }

  function refreshUI() {
    let data;
    try {
      data = getAllVariables().stat_data;
    } catch(e) {
      return;
    }
    if (!data) return;

    const jn = data['姜南'] || {};
    const ledger = data['帳本'] || {};

    const xd = typeof jn['心動'] === 'number' ? jn['心動'] : null;
    const guilt = typeof jn['愧疚'] === 'number' ? jn['愧疚'] : null;
    const mask = typeof jn['面具'] === 'number' ? jn['面具'] : null;
    const capital = typeof ledger['本金'] === 'number' ? ledger['本金'] : null;
    const mud = typeof ledger['泥碼'] === 'number' ? ledger['泥碼'] : null;
    const debt = typeof ledger['欠債'] === 'number' ? ledger['欠債'] : null;

    if (xd === null && guilt === null && mask === null) return;

    document.getElementById('jnLoading').style.display = 'none';
    document.getElementById('jnStats').style.display = '';
    document.getElementById('jnDiv2').style.display = '';
    document.getElementById('jnLedger').style.display = '';
    document.getElementById('jnFreedom').style.display = '';
    document.getElementById('jnDiv3').style.display = '';
    document.getElementById('jnFooter').style.display = '';

    if (xd !== null) {
      document.getElementById('jnXd').style.width = xd + '%';
      document.getElementById('jnXdV').textContent = xd;
    }
    if (guilt !== null) {
      document.getElementById('jnGuilt').style.width = guilt + '%';
      document.getElementById('jnGuiltV').textContent = guilt;
    }
    if (mask !== null) {
      document.getElementById('jnMask').style.width = mask + '%';
      document.getElementById('jnMaskV').textContent = mask;
    }

    if (capital !== null) document.getElementById('jnCapital').textContent = formatMoney(capital);
    if (mud !== null) document.getElementById('jnMud').textContent = formatMoney(mud);
    if (debt !== null) {
      document.getElementById('jnDebt').textContent = formatMoney(debt);
      const pct = Math.max(0, Math.min(100, ((DEBT_TOTAL - debt) / DEBT_TOTAL) * 100));
      document.getElementById('jnFreePct').textContent = Math.round(pct) + '%';
      document.getElementById('jnFreeFill').style.width = pct + '%';

      const card = document.getElementById('jnCard');
      if (debt === 0) {
        card.classList.add('free');
        document.getElementById('jnFreeLabel').innerHTML = '🆓 自由';
        /* 保留 debt class 以讓 .free .debt CSS 變色規則生效 */
      } else {
        card.classList.remove('free');
        document.getElementById('jnFreeLabel').innerHTML = '距離自由';
      }
    }
  }

  function setPage() {
    try {
      const id = typeof getCurrentMessageId === 'function' ? getCurrentMessageId() : 0;
      document.getElementById('jnPage').textContent = padPage(id);
    } catch(e) {}
  }

  /* 啟動時自動展開 */
  const card = document.getElementById('jnCard');
  if (card) card.classList.add('open');

  /* 等待 MVU 初始化 */
  try {
    if (typeof waitGlobalInitialized === 'function') {
      await waitGlobalInitialized('Mvu');
    }
  } catch(e) {}

  refreshUI();
  setPage();

  /* 用 bundle 事件 UPDATE_ENDED 刷新（不用 setInterval 輪詢） */
  let bound = false;
  try {
    const Mvu = window.parent.Mvu;
    if (Mvu && Mvu.events && typeof eventOn === 'function') {
      eventOn(Mvu.events.VARIABLE_UPDATE_ENDED, function() {
        refreshUI();
      });
      bound = true;
    } else if (Mvu && Mvu.events && typeof window.parent.eventOn === 'function') {
      window.parent.eventOn(Mvu.events.VARIABLE_UPDATE_ENDED, function() {
        refreshUI();
      });
      bound = true;
    }
  } catch(e) {}

  if (!bound) {
    setInterval(refreshUI, 3000);
  }
})();
</script>
</body>

