import { registerMvuSchema } from 'https://testingcf.jsdelivr.net/gh/StageDog/tavern_resource/dist/util/mvu_zod.js';

export const Schema = z.object({
  姜南: z.object({
    心動: z.coerce.number().prefault(0),
    愧疚: z.coerce.number().prefault(0),
    面具: z.coerce.number().prefault(100),
    風聲已起: z.boolean().prefault(false),
  }).transform(data => {
    let 心動 = Math.round(_.clamp(data.心動, 0, 100));
    let 愧疚 = Math.round(_.clamp(data.愧疚, 0, 100));
    let 面具 = Math.round(_.clamp(data.面具, 0, 100));
    /* 聯動條令：面具完好時不讓自己越線 */
    if (面具 > 50) {
      心動 = Math.min(心動, 69);
    }
    /* 劇情鎖：未經風聲事件不會愛到底 */
    if (!data.風聲已起) {
      心動 = Math.min(心動, 89);
    }
    return { 心動, 愧疚, 面具, 風聲已起: data.風聲已起 };
  }),
  帳本: z.object({
    本金: z.coerce.number().prefault(35000),
    泥碼: z.coerce.number().prefault(0),
    欠債: z.coerce.number().prefault(3500000),
  }).transform(data => ({
    本金: Math.max(0, Math.round(data.本金)),
    泥碼: Math.max(0, Math.round(data.泥碼)),
    欠債: Math.max(0, Math.round(data.欠債)),
  })),
});

$(() => {
  registerMvuSchema(Schema);
});

/*
  洋樓選單按鈕腳本
