});

$(async function() {
  /* ══════════════════════════════════════════════════════
   * 姜南真骰引擎 v1.0.0
   * 七戲公正 RNG ＋ 帳本直寫 ＋ 換桌世界書切換
   * ══════════════════════════════════════════════════════
   * 禁止簡繁轉換：所有按鈕名、條目名以本檔為準
   * 賭戀分離保證：本檔不讀取、不引用任何感情值
   * ══════════════════════════════════════════════════════ */

  await waitGlobalInitialized('Mvu');

  /* ────────── 1. 常量 ────────── */

  var MANAGED_RULES = [
    '【規則】百家樂',
    '【規則】輪盤',
    '【規則】骰寶',
    '【規則】拉霸機',
    '【規則】射龍門龍虎牛牛',
    '【規則】德州撲克'
  ];

  var TABLE_MAP = {
    '拉霸':       MANAGED_RULES[3],
    '百家樂': MANAGED_RULES[0],
    '輪盤':       MANAGED_RULES[1],
    '骰寶':       MANAGED_RULES[2],
    '龍虎':       MANAGED_RULES[4],
    '射龍門': MANAGED_RULES[4],
    '牛牛':       MANAGED_RULES[4],
    '德撲敘事桌': MANAGED_RULES[5]
  };

  var ENGINE_GAMES = [
    '拉霸','百家樂','輪盤',
    '骰寶','龍虎','射龍門','牛牛'
  ];

  var currentTable = '百家樂';

  var RED_NUMBERS = [1,3,5,7,9,12,14,16,18,19,21,23,25,27,30,32,34,36];

  var SLOT_SYMBOLS = ['💎','⭐','🔔','🍒','🍋'];

  /* RTP ~92% 加權結果表 [累積機率, 倍率, 符號, 層級] */
  var SLOT_TABLE = [
    [0.001,  200, [0,0,0], '頭獎'],
    [0.004,  40,  [1,1,1], '大獎'],
    [0.021,  8,   [2,2,2], '中獎'],
    [0.081,  3,   [3,3,3], '小獎'],
    [0.201,  1.5, [3,3,4], '安慰'],
    [0.401,  0.5, [3,4,2], '微中'],
    [1.0,    0,   null,    '未中']
  ];

  /* 牛牛翻倍表（照規則書：牛8=2x, 牛9=3x, 牛牛=5x） */
  var NIU_MULT = [1,1,1,1,1,1,1,1,2,3,5];

  /* QR 自動建集（單一來源，與姜南_QR集.json 同步） */
  var QR_SET = '姜南_洋樓_v2';
  var QR_PREFIX = '姜南_洋樓_v';
  /* 歷史命名相容：v1 自動建用無底線、手動匯入用有底線，兩種都要清 */
  var QR_OLD_PREFIXES = ['姜南_洋樓_v', '姜南洋樓_v'];
  var QR_ENTRIES = [
    {l:'🏮 洋樓',  t:'打開洋樓平面圖選單', c:'/send <yanglou_menu/>'},
    {l:'📖 全開',  t:'一鍵開啟所有規則書', c:'/send 【規則全開】'},
    {l:'🃏 百家樂',t:'切換到百家樂桌',     c:'/send 【換桌】百家樂'},
    {l:'🎡 輪盤',  t:'切換到輪盤桌',       c:'/send 【換桌】輪盤'},
    {l:'🎲 骰寶',  t:'切換到骰寶桌',       c:'/send 【換桌】骰寶'},
    {l:'🎰 拉霸',  t:'切換到拉霸機走廊',   c:'/send 【換桌】拉霸'},
    {l:'🐉 龍虎',  t:'切換到龍虎桌',       c:'/send 【換桌】龍虎'},
    {l:'🚪 射龍門',t:'切換到射龍門桌',     c:'/send 【換桌】射龍門'},
    {l:'🐂 牛牛',  t:'切換到牛牛桌',       c:'/send 【換桌】牛牛'}
  ];

  /* ────────── 2. RNG 工具 ────────── */

  function ri(min, max) {
    return Math.floor(Math.random() * (max - min + 1)) + min;
  }

  function shuffle(a) {
    a = a.slice();
    for (var i = a.length - 1; i > 0; i--) {
      var j = ri(0, i);
      var t = a[i]; a[i] = a[j]; a[j] = t;
    }
    return a;
  }

  function deck52() {
    var d = [];
    var ss = ['H','D','C','S'];
    for (var s = 0; s < 4; s++)
      for (var r = 1; r <= 13; r++)
        d.push([r, ss[s]]);
    return shuffle(d);
  }

  function dice3() { return [ri(1,6), ri(1,6), ri(1,6)]; }

  function cv(r) { return r >= 10 ? 0 : r; }

  function rn(r) {
    if (r === 1) return 'A';
    if (r === 11) return 'J';
    if (r === 12) return 'Q';
    if (r === 13) return 'K';
    return String(r);
  }

  function ss(s) { return {H:'♥',D:'♦',C:'♣',S:'♠'}[s]||s; }

  function cs(c) { return rn(c[0]) + ss(c[1]); }

  function css(arr) { return arr.map(cs).join(' '); }

  /* ────────── 3. 七戲引擎 ────────── */

  function engBac(bt, ba) {
    var d = deck52(), di = 0;
    var pc = [d[di++], d[di++]];
    var bc = [d[di++], d[di++]];
    var pp = (cv(pc[0][0]) + cv(pc[1][0])) % 10;
    var bp = (cv(bc[0][0]) + cv(bc[1][0])) % 10;
    var nat = pp >= 8 || bp >= 8;

    if (!nat) {
      var drew = false, pt = null;
      if (pp <= 5) {
        pt = d[di++]; pc.push(pt); pp = (pp + cv(pt[0])) % 10; drew = true;
      }
      if (!drew) {
        if (bp <= 5) { var t = d[di++]; bc.push(t); bp = (bp + cv(t[0])) % 10; }
      } else {
        var pv = cv(pt[0]), dr = false;
        if (bp <= 2) dr = true;
        else if (bp === 3 && pv !== 8) dr = true;
        else if (bp === 4 && pv >= 2 && pv <= 7) dr = true;
        else if (bp === 5 && pv >= 4 && pv <= 7) dr = true;
        else if (bp === 6 && (pv === 6 || pv === 7)) dr = true;
        if (dr) { var t2 = d[di++]; bc.push(t2); bp = (bp + cv(t2[0])) % 10; }
      }
    }

    var w = bp > pp ? 'banker' : pp > bp ? 'player' : 'tie';
    var pay = -ba, push = false;

    if (bt === '莊') {
      if (w === 'banker') pay = Math.floor(ba * 0.95);
      else if (w === 'tie') { pay = 0; push = true; }
    } else if (bt === '閒') {
      if (w === 'player') pay = ba;
      else if (w === 'tie') { pay = 0; push = true; }
    } else if (bt === '和') {
      if (w === 'tie') pay = ba * 8;
    } else if (bt === '莊對') {
      if (bc[0][0] === bc[1][0]) pay = ba * 11;
    } else if (bt === '閒對') {
      if (pc[0][0] === pc[1][0]) pay = ba * 11;
    }

    return { g:'bac', r:{bc:bc,bp:bp,pc:pc,pp:pp,w:w,nat:nat}, payout:pay, push:push };
  }

  function engRou(bt, ba) {
    var n = ri(0, 36);
    var c = n === 0 ? 'green' : RED_NUMBERS.indexOf(n) >= 0 ? 'red' : 'black';
    var pay = -ba;
    var num = parseInt(bt);

    if (!isNaN(num) && num >= 0 && num <= 36) {
      if (n === num) pay = ba * 35;
    } else if (bt === '紅') {
      if (c === 'red') pay = ba;
    } else if (bt === '黑') {
      if (c === 'black') pay = ba;
    } else if (bt === '單') {
      if (n > 0 && n % 2 === 1) pay = ba;
    } else if (bt === '雙') {
      if (n > 0 && n % 2 === 0) pay = ba;
    } else if (bt === '大') {
      if (n >= 19) pay = ba;
    } else if (bt === '小') {
      if (n >= 1 && n <= 18) pay = ba;
    } else if (bt === '1打') {
      if (n >= 1 && n <= 12) pay = ba * 2;
    } else if (bt === '2打') {
      if (n >= 13 && n <= 24) pay = ba * 2;
    } else if (bt === '3打') {
      if (n >= 25 && n <= 36) pay = ba * 2;
    }

    return { g:'rou', r:{n:n,c:c}, payout:pay, push:false };
  }

  function engSic(bt, ba) {
    var d = dice3(), t = d[0]+d[1]+d[2];
    var triple = d[0]===d[1] && d[1]===d[2];
    var pay = -ba;

    if (bt === '大') {
      if (t >= 11 && t <= 17 && !triple) pay = ba;
    } else if (bt === '小') {
      if (t >= 4 && t <= 10 && !triple) pay = ba;
    } else if (bt === '全圍') {
      if (triple) pay = ba * 24;
    } else {
      var tn = parseInt(bt);
      if (!isNaN(tn) && tn >= 1 && tn <= 6) {
        var cnt = 0;
        for (var i = 0; i < 3; i++) if (d[i] === tn) cnt++;
        if (cnt === 1) pay = ba;
        else if (cnt === 2) pay = ba * 2;
        else if (cnt === 3) pay = ba * 3;
      }
    }

    return { g:'sic', r:{d:d,t:t,triple:triple}, payout:pay, push:false };
  }

  function engSlo(ba) {
    var roll = Math.random(), tier = SLOT_TABLE[SLOT_TABLE.length - 1];
    for (var i = 0; i < SLOT_TABLE.length; i++) {
      if (roll < SLOT_TABLE[i][0]) { tier = SLOT_TABLE[i]; break; }
    }

    var syms;
    if (tier[2]) {
      syms = tier[2].map(function(idx) { return SLOT_SYMBOLS[idx]; });
    } else {
      do {
        syms = [SLOT_SYMBOLS[ri(0,4)], SLOT_SYMBOLS[ri(0,4)], SLOT_SYMBOLS[ri(0,4)]];
      } while (syms[0]===syms[1] && syms[1]===syms[2]);
    }

    var pay = tier[1] > 0 ? Math.round(ba * tier[1]) - ba : -ba;
    return { g:'slo', r:{s:syms, tier:tier[3], mult:tier[1]}, payout:pay, push:false };
  }

  function engRdg(ba) {
    var dk = deck52();
    var g1 = dk[0], g2 = dk[1], shot = dk[2];
    var lo = Math.min(g1[0], g2[0]), hi = Math.max(g1[0], g2[0]);
    var sr = shot[0];
    var hit = (sr === lo || sr === hi);
    var inG = sr > lo && sr < hi;
    var pay = hit ? -ba * 2 : inG ? ba : -ba;

    return { g:'rdg', r:{g1:g1,g2:g2,shot:shot,lo:lo,hi:hi,hit:hit,inG:inG}, payout:pay, push:false };
  }

  function engDrt(bt, ba) {
    var dk = deck52();
    var dr = dk[0], ti = dk[1];
    var w = dr[0] > ti[0] ? 'dragon' : ti[0] > dr[0] ? 'tiger' : 'tie';
    var pay = -ba;

    if (bt === '龍' && w === 'dragon') pay = ba;
    else if (bt === '虎' && w === 'tiger') pay = ba;
    else if (bt === '和' && w === 'tie') pay = ba * 8;
    else if (w === 'tie' && bt !== '和') pay = -Math.floor(ba / 2);

    return { g:'drt', r:{dragon:dr,tiger:ti,w:w}, payout:pay, push:false };
  }

  function engNiu(ba) {
    var dk = deck52();
    var pc = dk.slice(0, 5), dc = dk.slice(5, 10);

    function nv(r) { return r > 10 ? 10 : r; }
    function calc(cards) {
      for (var i = 0; i < 3; i++)
        for (var j = i+1; j < 4; j++)
          for (var k = j+1; k < 5; k++) {
            if ((nv(cards[i][0])+nv(cards[j][0])+nv(cards[k][0])) % 10 === 0) {
              var rest = [];
              for (var m = 0; m < 5; m++) if (m!==i&&m!==j&&m!==k) rest.push(cards[m]);
              var s2 = (nv(rest[0][0])+nv(rest[1][0])) % 10;
              return s2 === 0 ? 10 : s2;
            }
          }
      return 0;
    }

    var pn = calc(pc), dn = calc(dc);
    var pw;
    if (pn > dn) pw = true;
    else if (pn < dn) pw = false;
    else {
      var pMax = Math.max.apply(null, pc.map(function(c){return c[0];}));
      var dMax = Math.max.apply(null, dc.map(function(c){return c[0];}));
      pw = pMax > dMax;
    }

    var mult = NIU_MULT[pw ? pn : dn] || 1;
    var pay = pw ? ba * mult : -ba * mult;

    return { g:'niu', r:{pc:pc,dc:dc,pn:pn,dn:dn,pw:pw}, payout:pay, push:false };
  }

  /* ────────── 4. 帳本操作 ────────── */

  function readLedger() {
    try {
      var d = Mvu.getMvuData({type:'message'});
      if (d && d.stat_data && d.stat_data['帳本']) return d.stat_data['帳本'];
    } catch(e) {}
    return {'本金':35000,'泥碼':0,'欠債':3500000};
  }

  function writeLedger(nL) {
    try {
      var d = Mvu.getMvuData({type:'message'});
      if (!d||!d.stat_data) return false;
      d.stat_data['帳本'] = {
        '本金': Math.max(0, Math.round(nL['本金'])),
        '泥碼': Math.max(0, Math.round(nL['泥碼'])),
        '欠債': Math.max(0, Math.round(nL['欠債']))
      };
      Mvu.replaceMvuData(d, {type:'message'});
      return true;
    } catch(e) { return false; }
  }

  function deduct(ledger, amt) {
    var fm = Math.min(ledger['泥碼']||0, amt);
    return { fm:fm, fp:amt-fm };
  }

  function applyResult(ledger, ded, pay, push) {
    var nL = {
      '本金': ledger['本金'] - ded.fp,
      '泥碼': ledger['泥碼'] - ded.fm,
      '欠債': ledger['欠債']
    };
    if (push) {
      nL['本金'] += ded.fp;
      nL['泥碼'] += ded.fm;
    } else if (pay > 0) {
      nL['泥碼'] += ded.fm;
      nL['本金'] += ded.fp + pay;
    }
    return nL;
  }

  /* ────────── 5. 結果文字 ────────── */

  var GNAME = {
    bac:'百家樂', rou:'輪盤', sic:'骰寶',
    slo:'拉霸機', rdg:'射龍門',
    drt:'龍虎鬥', niu:'牛牛'
  };
  var WNAME = {banker:'莊贏',player:'閒贏',tie:'和局',
               dragon:'龍贏',tiger:'虎贏'};

  function niuN(v) {
    if (v===0) return '無牛';
    if (v===10) return '牛牛';
    return '牛'+v;
  }

  function resText(game, bt, ba, res, bL, aL) {
    var ln = ['【引擎結果】' + (GNAME[res.g]||game)];
    var r = res.r;

    if (res.g==='bac') {
      ln.push('莊家 '+r.bp+' 點（'+css(r.bc)+'）');
      ln.push('閒家 '+r.pp+' 點（'+css(r.pc)+'）');
      ln.push('結果：'+(WNAME[r.w]||r.w));
      if (r.nat) ln.push('天牌（Natural）');
    } else if (res.g==='rou') {
      ln.push('號碼：'+r.n+'（'+{red:'紅',black:'黑',green:'綠'}[r.c]+'）');
    } else if (res.g==='sic') {
      ln.push('骰面：'+r.d.join('、')+'（合計 '+r.t+'）');
      if (r.triple) ln.push('全圍！');
    } else if (res.g==='slo') {
      ln.push('轉輪：'+r.s.join(' '));
      ln.push(r.tier+(r.mult>0?'（'+r.mult+'倍）':''));
    } else if (res.g==='rdg') {
      ln.push('門柱：'+cs(r.g1)+' — '+cs(r.g2));
      ln.push('射門：'+cs(r.shot));
      if (r.hit) ln.push('撞柱！包賠雙倍');
      else if (r.inG) ln.push('進門');
      else ln.push('出界');
    } else if (res.g==='drt') {
      ln.push('龍：'+cs(r.dragon)+'　虎：'+cs(r.tiger));
      ln.push('結果：'+(WNAME[r.w]||r.w));
    } else if (res.g==='niu') {
      ln.push('玩家：'+css(r.pc)+'→'+niuN(r.pn));
      ln.push('莊家：'+css(r.dc)+'→'+niuN(r.dn));
      ln.push(r.pw?'玩家勝':'莊家勝');
    }

    var net = res.payout;
    if (res.push) ln.push('下注 '+ba+'→退注');
    else if (net>0) ln.push('下注 '+ba+'→贏 '+Math.round(net));
    else ln.push('下注 '+ba+'→輸 '+Math.abs(Math.round(net)));

    ln.push('帳本：本金 '+aL['本金']+
            '｜泥碼 '+aL['泥碼']+
            '｜欠債 '+aL['欠債']);
    return ln.join('\n');
  }

  /* ────────── 6. 世界書切換 ────────── */

  async function getWb() {
    try {
      if (typeof TavernHelper!=='undefined' && TavernHelper.getCurrentCharPrimaryLorebook)
        return await TavernHelper.getCurrentCharPrimaryLorebook();
    } catch(e){}
    try {
      var n = await getCharWorldbookNames('current');
      return n && n.primary;
    } catch(e){}
    return null;
  }

  async function switchRules(target) {
    var wb = await getWb();
    if (!wb) { toastr.error('找不到世界書','換桌失敗'); return false; }
    try {
      var entries = await TavernHelper.getLorebookEntries(wb);
      var updates = [], logs = [];
      (entries||[]).forEach(function(e) {
        var c = e.comment||'';
        if (MANAGED_RULES.indexOf(c)<0) return;
        var want = (c === target);
        if (e.enabled !== want) {
          updates.push({uid:e.uid, enabled:want});
          logs.push((want?'✅':'🚫')+' '+c);
        }
      });
      if (updates.length>0) await TavernHelper.setLorebookEntries(wb, updates);
      if (logs.length>0) {
        toastr.success('📖 已切換至'+(target||'離桌')+'<br>'+logs.join('<br>'),
          '世界書切換', {timeOut:4000,escapeHtml:false,preventDuplicates:true});
      }
      return true;
    } catch(e) {
      toastr.error('世界書寫入失敗：'+(e.message||e),'換桌失敗');
      return false;
    }
  }

  async function enableAll() {
    var wb = await getWb();
    if (!wb) { toastr.error('找不到世界書','規則全開失敗'); return; }
    try {
      var entries = await TavernHelper.getLorebookEntries(wb);
      var updates = [];
      (entries||[]).forEach(function(e) {
        if (MANAGED_RULES.indexOf(e.comment||'')<0) return;
        if (!e.enabled) updates.push({uid:e.uid,enabled:true});
      });
      if (updates.length>0) {
        await TavernHelper.setLorebookEntries(wb, updates);
        toastr.success('📖 六本規則書已全部開啟','規則全開',{timeOut:3000});
      } else {
        toastr.info('📖 規則書已全部開啟，無需變更','規則全開',{timeOut:3000});
      }
    } catch(e) {
      toastr.error('寫入失敗：'+(e.message||e),'規則全開失敗');
    }
  }

  async function disableAll() {
    var wb = await getWb();
    if (!wb) return;
    try {
      var entries = await TavernHelper.getLorebookEntries(wb);
      var updates = [];
      (entries||[]).forEach(function(e) {
        if (MANAGED_RULES.indexOf(e.comment||'')<0) return;
        if (e.enabled) updates.push({uid:e.uid,enabled:false});
      });
      if (updates.length>0) await TavernHelper.setLorebookEntries(wb, updates);
    } catch(e) {}
  }

  /* ────────── 7. 下注流程 ────────── */

  async function handleBet() {
    if (!currentTable || ENGINE_GAMES.indexOf(currentTable)<0) {
      if (currentTable==='簽泥碼') return handleSign();
      if (currentTable==='還債') return handleRepay();
      if (currentTable==='德撲敘事桌') {
        toastr.info('德撲為敘事桌，請直接對話','德撲敘事桌');
        return;
      }
      toastr.warning('請先從洋樓選單選擇一張桌子','未入座');
      return;
    }

    var ledger = readLedger();
    var funds = (ledger['泥碼']||0) + (ledger['本金']||0);
    var bt = '', ba;

    if (currentTable==='百家樂') {
      bt = prompt('下注項目（莊／閒／和／莊對／閒對）：');
      if (!bt) return;
      if (['莊','閒','和','莊對','閒對'].indexOf(bt)<0) {
        toastr.error('無效的下注項目','下注失敗'); return;
      }
    } else if (currentTable==='輪盤') {
      bt = prompt('下注項目（紅／黑／單／雙／大／小／1打／2打／3打／0-36 單號）：');
      if (!bt) return;
    } else if (currentTable==='骰寶') {
      bt = prompt('下注項目（大／小／全圍／1-6 指定單點）：');
      if (!bt) return;
    } else if (currentTable==='龍虎') {
      bt = prompt('下注項目（龍／虎／和）：');
      if (!bt) return;
      if (['龍','虎','和'].indexOf(bt)<0) {
        toastr.error('無效的下注項目','下注失敗'); return;
      }
    }

    var as = prompt('下注金額：');
    if (!as) return;
    ba = parseInt(as);
    if (isNaN(ba)||ba<=0) { toastr.error('金額必須為正整數','下注失敗'); return; }

    /* 保證金檢查 */
    if (currentTable==='牛牛' && ba*5>funds) {
      toastr.error('牛牛需要足夠支付最大 5 倍賠率的保證金（需 '+ba*5+'）','下注失敗'); return;
    } else if (currentTable==='射龍門' && ba*2>funds) {
      toastr.error('射龍門需要足夠支付撞柱雙倍罰款的保證金（需 '+ba*2+'）','下注失敗'); return;
    } else if (ENGINE_GAMES.indexOf(currentTable)>=0 && currentTable!=='牛牛' && currentTable!=='射龍門' && ba>funds) {
      toastr.error('資金不足（可用 '+funds+'），請前往結算室簽泥碼','下注失敗'); return;
    }

    /* 初始扣款計算 */
    var ded = deduct(ledger, ba);

    /* 跑引擎 */
    var res;
    if (currentTable==='百家樂') res = engBac(bt, ba);
    else if (currentTable==='輪盤') res = engRou(bt, ba);
    else if (currentTable==='骰寶') res = engSic(bt, ba);
    else if (currentTable==='拉霸') res = engSlo(ba);
    else if (currentTable==='射龍門') res = engRdg(ba);
    else if (currentTable==='龍虎') res = engDrt(bt, ba);
    else if (currentTable==='牛牛') res = engNiu(ba);
    if (!res) return;

    /* 特殊扣款（撞柱／牛牛輸） */
    var actualPay = res.payout;
    if (res.g==='rdg' && res.r.hit) {
      ded = deduct(ledger, ba * 2);
      actualPay = 0;
    }
    if (res.g==='niu' && !res.r.pw) {
      var lossMult = NIU_MULT[res.r.dn]||1;
      ded = deduct(ledger, ba * lossMult);
      actualPay = 0;
    }

    /* 帳本變動 */
    var nL = applyResult(ledger, ded, actualPay>0?actualPay:0, res.push);

    /* 直寫帳本 */
    writeLedger(nL);

    /* 結果文字 */
    var txt = resText(currentTable, bt, ba, res, ledger, nL);

    /* base64 編碼結果資料 */
    var rd = {
      g:res.g, b:{t:bt,a:ba}, d:{m:ded.fm,p:ded.fp}, r:res.r, w:res.payout,
      l:{bp:ledger['本金'],bm:ledger['泥碼'],bd:ledger['欠債'],
         ap:nL['本金'],am:nL['泥碼'],ad:nL['欠債']}
    };
    var b64 = btoa(unescape(encodeURIComponent(JSON.stringify(rd))));

    /* 組合訊息 */
    var cmd = '【開局】' + currentTable;
    if (bt) cmd += '｜' + bt;
    cmd += '｜' + ba;

    sendMsg(cmd + '\n<jn_result data="' + b64 + '"/>\n<jn_result_text>\n' + txt + '\n</jn_result_text>');
  }

  async function handleSign() {
    var ledger = readLedger();
    var as = prompt('簽泥碼金額（將增加等額欠債）：');
    if (!as) return;
    var amt = parseInt(as);
    if (isNaN(amt)||amt<=0) { toastr.error('金額必須為正整數','簽泥碼失敗'); return; }

    var nL = {
      '本金':ledger['本金'],
      '泥碼':ledger['泥碼']+amt,
      '欠債':ledger['欠債']+amt
    };
    writeLedger(nL);

    var txt = '【結算】簽泥碼 '+amt+
              '\n泥碼 '+ledger['泥碼']+'→'+nL['泥碼']+
              '｜欠債 '+ledger['欠債']+'→'+nL['欠債'];

    var rd = {g:'settle',type:'sign',amount:amt,
      l:{bp:ledger['本金'],bm:ledger['泥碼'],bd:ledger['欠債'],
         ap:nL['本金'],am:nL['泥碼'],ad:nL['欠債']}};
    var b64 = btoa(unescape(encodeURIComponent(JSON.stringify(rd))));

    sendMsg('【換桌】簽泥碼\n<jn_result data="'+b64+'"/>\n<jn_result_text>\n'+txt+'\n</jn_result_text>');
  }

  async function handleRepay() {
    var ledger = readLedger();
    if (ledger['欠債']<=0) { toastr.info('沒有欠債','還債'); return; }

    var cap = Math.min(ledger['本金'], ledger['欠債']);
    var as = prompt('還債金額（從本金扣除，上限 '+cap+'）：');
    if (!as) return;
    var amt = parseInt(as);
    if (isNaN(amt)||amt<=0) { toastr.error('金額必須為正整數','還債失敗'); return; }
    if (amt>ledger['本金']) { toastr.error('本金不足','還債失敗'); return; }
    if (amt>ledger['欠債']) amt = ledger['欠債'];

    var nL = {
      '本金':ledger['本金']-amt,
      '泥碼':ledger['泥碼'],
      '欠債':ledger['欠債']-amt
    };
    writeLedger(nL);

    var free = nL['欠債']===0;
    var txt = '【結算】還債 '+amt+
              '\n本金 '+ledger['本金']+'→'+nL['本金']+
              '｜欠債 '+ledger['欠債']+'→'+nL['欠債'];
    if (free) txt += '\n🆓 欠債歸零——自由結局觸發';

    var rd = {g:'settle',type:'repay',amount:amt,freedom:free,
      l:{bp:ledger['本金'],bm:ledger['泥碼'],bd:ledger['欠債'],
         ap:nL['本金'],am:nL['泥碼'],ad:nL['欠債']}};
    var b64 = btoa(unescape(encodeURIComponent(JSON.stringify(rd))));

    sendMsg('【換桌】還債\n<jn_result data="'+b64+'"/>\n<jn_result_text>\n'+txt+'\n</jn_result_text>');
  }

  function sendMsg(text) {
    var ta = $('#send_textarea');
    var btn = $('#send_but');
    if (ta.length && btn.length) { ta.val(text); btn.click(); }
  }

  /* ────────── 8. 換桌處理 ────────── */

  async function onSwitch(text) {
    var m = text.match(/【換桌】(.+)/);
    if (!m) return;
    var tgt = m[1].trim();

    if (tgt === '離桌') {
      currentTable = null;
      await disableAll();
      toastr.info('已離桌，規則書全關','離桌');
      return;
    }
    if (tgt==='簽泥碼'||tgt==='還債') { currentTable = tgt; return; }

    var rule = TABLE_MAP[tgt];
    if (!rule) { toastr.warning('未知的桌台：'+tgt,'換桌'); return; }
    var ok = await switchRules(rule);
    if (ok) { currentTable = tgt; }
    else { toastr.warning('世界書切換失敗，桌台未變更','換桌'); }
  }

  /* ────────── 9. QR 自動建集（安靜降級） ────────── */

  async function setupQR() {
    try {
      if (typeof triggerSlash !== 'function') {
        console.log('[Engine] triggerSlash unavailable, skip QR auto-build');
        return;
      }

      /* 列出所有集，檢查是否已存在 */
      var raw = await triggerSlash('/qr-set-list');
      var sets = [];
      try { sets = JSON.parse(raw || '[]'); } catch(e) { return; }

      if (sets.indexOf(QR_SET) >= 0) {
        /* 同版本已存在→冪等：只確保 chat 綁定 */
        await triggerSlash('/qr-chat-set-on visible=true ' + QR_SET);
        console.log('[Engine] QR set exists, rebound: ' + QR_SET);
        return;
      }

      /* 刪除舊版本（掃兩種歷史命名：有底線＋無底線） */
      for (var i = 0; i < sets.length; i++) {
        var isOld = false;
        for (var p = 0; p < QR_OLD_PREFIXES.length; p++) {
          if (sets[i].indexOf(QR_OLD_PREFIXES[p]) === 0 && sets[i] !== QR_SET) {
            isOld = true; break;
          }
        }
        if (isOld) {
          console.log('[Engine] Removing old QR set: ' + sets[i]);
          try { await triggerSlash('/qr-chat-set-off ' + sets[i]); } catch(e2) {}
          try { await triggerSlash('/qr-set-delete ' + sets[i]); } catch(e2) {}
        }
      }

      /* 建集 */
      await triggerSlash('/qr-set-create nosend=false ' + QR_SET);

      /* 建鍵（九項） */
      for (var j = 0; j < QR_ENTRIES.length; j++) {
        var e = QR_ENTRIES[j];
        await triggerSlash('/qr-create set="' + QR_SET +
          '" label="' + e.l + '" title="' + e.t + '" ' + e.c);
      }

      /* chat 範圍綁定 */
      await triggerSlash('/qr-chat-set-on visible=true ' + QR_SET);

      console.log('[Engine] QR set created and bound: ' + QR_SET);
    } catch(e) {
      console.log('[Engine] QR auto-build failed (safe to ignore): ' +
        (e && e.message ? e.message : e));
    }
  }

  /* ────────── 10. 初始化 ────────── */

  /* 禁止簡繁轉換：🎲 下注 */
  var evBet = getButtonEvent('🎲 下注');
  eventOn(evBet, function() { handleBet(); });

  /* 禁止簡繁轉換：📖 規則全開 */
  var evRescue = getButtonEvent('📖 規則全開');
  eventOn(evRescue, function() { enableAll(); });

  /* 監聽換桌指令 */
  try {
    eventOn('MESSAGE_SENT', function(msgId) {
      setTimeout(async function() {
        try {
          var last = await getChatMessages(-1);
          var t = '';
          if (last && typeof last === 'object') t = last.mes||last.message||'';
          if (typeof last === 'string') t = last;
          if (t.indexOf('【換桌】')>=0) onSwitch(t);
          if (t.indexOf('【規則全開】')>=0) enableAll();
        } catch(e) { console.log('[Engine] MSG_SENT err', e); }
      }, 150);
    });
  } catch(e) { console.log('[Engine] Cannot listen MESSAGE_SENT', e); }

  /* 攔截模型對帳本的修改 */
  try {
    eventOn(Mvu.events.COMMAND_PARSED, function(vars, commands) {
      if (!currentTable || ENGINE_GAMES.indexOf(currentTable)<0) return;
      for (var i = commands.length-1; i >= 0; i--) {
        if ((commands[i].path||'').indexOf('帳本')>=0) commands.splice(i,1);
      }
    });
  } catch(e) {}

  /* CHAT_CHANGED 重新綁定 QR 到新聊天 */
  try {
    eventOn('CHAT_CHANGED', function() {
      if (typeof triggerSlash === 'function') {
        triggerSlash('/qr-chat-set-on visible=true ' + QR_SET).catch(function(){});
      }
    });
  } catch(e) {}

  console.log('[Engine] init ok, table=' + currentTable);

  /* QR 自動建集（fire-and-forget，錯誤內部吞掉） */
  setupQR();
});
